queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?exchange_traded_products a :Exchange_traded_Products .
    ?exchange_traded_products p:ProductName ?productname .
    BIND(?productname AS ?o0)
  }
  UNION
  {
    ?unit_investment_trusts a :Unit_investment_Trusts .
    ?unit_investment_trusts p:TrustName ?trustname .
    ?unit_investment_trusts p:ExitFee ?exitfee_f .
    FILTER((STR(?exitfee_f) = "0.01"))
    BIND(?trustname AS ?o0)
  }
}

